#include<bits/stdc++.h>
using namespace std;
vector<long long> mp[105];
long long n,m,t;
long long in[105];
const long long mod=998244353;
struct matrix
{
    long long a[105][105];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=1;i<=102;i++)
        {
            for(long long j=1;j<=102;j++)
            {
                for(long long k=1;k<=102;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%mod)*(b.a[k][j]%mod)%mod;
                    c.a[i][j]%=mod;
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    ans.a[1][n+2]=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    base=ans=matrix();
    scanf("%lld%lld%lld",&n,&m,&t);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&base.a[i][i]);
    }
    for(long long i=1;i<=m;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        in[y]++;
        base.a[x][y]=1;
    }
    for(long long i=1;i<=n;i++)
    {
        if(in[i]==0)
        {
            base.a[n+1][i]=base.a[n+2][i]=1;
        }
    }
    base.a[n+1][n+1]=base.a[n+2][n+1]=base.a[n+2][n+2]=1;
    fastpow(t);
    for(long long i=1;i<=n;i++)
    {
        printf("%lld ",ans.a[1][i]);
    }
    return 0;
}
